// Created: 2026-05-22

/**
 * Goal Convergence Emitter — Stop hook (M168 Phase 3, #1913)
 *
 * Layer 3 of the 4-layer coordination architecture. Reads the
 * project-local `goal-current.json` to detect a /goal that converged
 * on this turn. When detected:
 *
 *   1. Appends a `goal_converged` event to the cross-session
 *      `~/.local/state/orchestkit/events.jsonl` log.
 *   2. Appends a closing line to the per-repo
 *      `.claude/state/goal-history.jsonl` for backwards-compat with
 *      M140 goal-tracker tooling. Idempotent — if the latest history
 *      line for this session is already a close, we skip.
 *
 * Hook event: Stop (async, timeout: 3s).
 */

import {
  appendFileSync,
  existsSync,
  mkdirSync,
  readFileSync,
} from 'node:fs';
import { createHash } from 'node:crypto';
import { dirname, join } from 'node:path';
import type { HookInput, HookResult, HookContext } from '../types.js';
import { outputSilentSuccess } from '../lib/common.js';
import { NOOP_CTX } from '../lib/context.js';
import { appendEvent } from '../lib/event-log.js';

const HOOK_NAME = 'stop/goal-convergence-emitter';
const GOAL_CURRENT_REL = join('.claude', 'state', 'goal-current.json');
const GOAL_HISTORY_REL = join('.claude', 'state', 'goal-history.jsonl');

interface GoalCurrent {
  session_id?: string;
  condition?: string;
  status?: 'converged' | 'spun' | 'aborted' | 'pending';
  started_at?: string;
  turn_count?: number;
  converged_at?: string;
}

function hashRepo(repoPath: string): string {
  return createHash('sha256').update(repoPath).digest('hex').slice(0, 12);
}

/**
 * True if the most-recent goal-history line for `sessionId` is already
 * a closing entry (has `ended_at`). Returning true means we've already
 * emitted convergence for this turn and should skip — idempotency.
 */
function lastIsClosedForSession(historyPath: string, sessionId: string): boolean {
  if (!existsSync(historyPath)) return false;
  let raw: string;
  try {
    raw = readFileSync(historyPath, 'utf8');
  } catch {
    return false;
  }
  const lines = raw.split(/\r?\n/).filter(l => l.trim().length > 0);
  for (let i = lines.length - 1; i >= 0; i--) {
    let parsed: { session_id?: string; ended_at?: string | null };
    try {
      parsed = JSON.parse(lines[i]);
    } catch {
      continue;
    }
    if (parsed.session_id !== sessionId) continue;
    return Boolean(parsed.ended_at);
  }
  return false;
}

export function goalConvergenceEmitter(
  input: HookInput,
  ctx: HookContext = NOOP_CTX,
): HookResult {
  const sid = input.session_id || ctx.sessionId;
  if (!sid) return outputSilentSuccess();

  const projectDir = ctx.projectDir;
  if (!projectDir) return outputSilentSuccess();

  const currentPath = join(projectDir, GOAL_CURRENT_REL);
  if (!existsSync(currentPath)) return outputSilentSuccess();

  let current: GoalCurrent;
  try {
    current = JSON.parse(readFileSync(currentPath, 'utf8')) as GoalCurrent;
  } catch (err) {
    ctx.log(HOOK_NAME, `parse failed: ${(err as Error).message}`, 'warn');
    return outputSilentSuccess();
  }

  if (current.status !== 'converged') return outputSilentSuccess();

  const historyPath = join(projectDir, GOAL_HISTORY_REL);
  // Idempotency: skip if the latest history line already closes this sid.
  if (lastIsClosedForSession(historyPath, sid)) {
    return outputSilentSuccess();
  }

  const nowMs = Date.now();
  const nowIso = new Date(nowMs).toISOString();

  // 1. Event log entry (cross-session bus).
  try {
    appendEvent({
      type: 'goal_converged',
      ts: nowMs,
      repo_hash: hashRepo(projectDir),
      sid,
      condition: current.condition,
      status: 'converged',
      turn_count: current.turn_count,
    });
  } catch (err) {
    ctx.log(HOOK_NAME, `event append failed: ${(err as Error).message}`, 'warn');
  }

  // 2. Per-repo history line (back-compat with M140 goal-tracker).
  const historyEntry = {
    session_id: sid,
    ended_at: current.converged_at || nowIso,
    status: 'converged' as const,
    turn_count: current.turn_count,
    condition: current.condition,
  };
  try {
    mkdirSync(dirname(historyPath), { recursive: true });
    appendFileSync(historyPath, `${JSON.stringify(historyEntry)}\n`, 'utf8');
    ctx.log(HOOK_NAME, `goal_converged emitted: sid=${sid}`);
  } catch (err) {
    ctx.log(HOOK_NAME, `history append failed: ${(err as Error).message}`, 'warn');
  }

  return outputSilentSuccess();
}

/** Exposed for tests. */
export const __internals = {
  GOAL_CURRENT_REL,
  GOAL_HISTORY_REL,
  lastIsClosedForSession,
};
